VALUES
  ('cpa-moex-00835', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於執行應收帳款控制測試，以確認應收帳款授信額度是否經適當人員核准。查核樣 本量為40，計算的偏差率上限設為5%。如在前10筆樣本中已發現8筆未經適當人員核准 ，此時查核人員最可能之因應方式為何？', '["繼續其他30筆樣本的測試", "重新計算樣本量大小", "增加可接受的偏差比率", "停止測試，重新設定應收帳款的控制風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00836', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關核閱財務報表所執行程序的敘述，下列何者錯誤？', '["核閱人員應向管理階層查詢截至財務報表日所發生可能須於財務報表中調整或揭露之事 項是否均已辨認", "核閱人員所執行之程序通常限於查詢（主要向受核閱者負責財務與會計事務之人員查詢） 、分析性程序及其他核閱程序", "核閱人員通常無須驗證管理階層對有關訴訟或索賠之查詢所作之回應，因此無須函詢受核 閱者之律師", "核閱人員仍應向管理階層取得書面聲明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00837', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何項為影響一般用途整體財務報表重大性的最主要因素？', '["查核人員的風險評估", "過去年度查核不實表達的程度", "財務報表一般使用者之經濟決策需求", "受查者同業過去三年常用的重大性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00838', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依照我國審計準則公報第 43 號之規定，查核人員為因應管理階層踰越控制之查核程序，而 複核可能導致重大不實表達之會計估計，其主要目的為何？', '["確定是否有跡象顯示管理階層所做之判斷及假設存有偏差", "懷疑查核人員基於當時取得資訊所做之專業判斷的正確性", "確定財務報表認列或揭露之公允價值會計估計是否合理", "判斷是否已有辨認出之會計估計因具高度估計不確定性而導致顯著風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00839', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司設置有完善的內部稽核部門且直接向財務長報告。該公司之內部稽核報告顯示，內部控 制皆依設計目的執行並能產生可靠之會計紀錄。依據前述，該公司之簽證會計師應如何因應？', '["可以不要再執行內部控制測試", "可以加強管理控制之瞭解與評估的深度", "避免重複內部稽核已經執行過的測試工作", "對於內部稽核所執行之測試給予有限度的信賴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00840', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司持有乙公司的80%之流通在外普通股，而對乙公司具有控制力，並另持有丙公司發行 之公司債總額的50%。甲、乙、丙三家公司的財務報表分別委託子、丑、寅三位會計師進行 查核。丑會計師為集團查核目的而對乙公司的財務報表執行查核工作，子會計師採用丑會計 師之查核工作，並經取得足夠及適切的查核證據後，認為該集團財務報表業已允當表達。下 列有關集團財務報表查核之敘述，何者錯誤？', '["子會計師應對集團之組成個體（乙公司）決定是否為其查核人員（丑會計師）之工作承擔責任", "若子會計師決定為丑會計師之工作承擔責任，則必須參與丑會計師之工作達可對集團財務 報表表示意見之程度，且不得於集團查核報告中提及丑會計師對乙公司財務報表之查核", "若子會計師決定不為丑會計師之工作承擔責任，應於集團查核報告中增列其他事項段提及 丑會計師之姓名及其對乙公司財務報表之查核", "無論集團查核報告是否提及組成個體查核人員之查核，集團查核意見均應由集團主辦會計 師（子會計師）負責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00841', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員對存貨期末餘額所執行之查核程序甚少能提供與期初餘額攸關之查核證據，故為取 得存貨期初餘額足夠及適切之查核證據，查核人員可能須額外執行之一項或多項工作，但較 不可能包括下列何者？', '["對期初存貨之評價執行查核程序", "對銷貨毛利及截止執行查核程序", "對期初存貨之權利執行查核程序", "觀察當期實體存貨盤點，並將其調節至期初存貨數量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00842', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '針對估計不確定性，下列敘述何者錯誤？①不確性越高，受管理階層偏頗影響之程度越', '["會計估計依據可觀察輸入值越多，其不確定性越高", "會計估計具高度不確定性 ，查核人員可能對此評估具顯著風險", "若查核人員認為管理階層未適當處理估計不確 定性對存有顯著風險會計估計之影響，於必要時應建立單一金額估計以評估該會計估計 之合理性", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00843', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員運用元單位抽樣方法（Monetary Unit Sampling, MUS）執行1,000個應收帳款明細 帳，共計$20,000,000之查核，下列敘述何者正確？', '["建立於常態分配", "適用於發生錯誤頻率高", "抽樣單位數有1,000個", "帳戶餘額愈高，被抽中機率愈大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00844', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列那些情況可納入查核報告中之強調事項段中，以提醒財務報表預期使用者注意？①提及', '["管理階層採用新會計政策追溯重編以前年度財務報表之影響", "補充說明財務報表附註未揭露事項", "重大期後併購交易事項", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00845', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何種情況下，會計師最有可能於財務報表發布後仍須採取進一步行動？', '["未決訟案終告判決確定", "受查者爆發重大員工侵占資產醜聞", "受查者因競爭對手推出新產品而發生重大經營危機，極可能倒閉", "發現經查核之財務報表所揭露之關係人交易不完整，且存在重大異常"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00846', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '會計師因財務報表存有重大不實表達而出具保留意見或否定意見之查核報告時，依我國審計 準則公報對下列查核報告內容敘述之規定，何者錯誤？', '["如表示保留意見時，保留意見段應敘明：「依本會計師之意見，除保留意見之基礎段所述 事項之可能影響外，上開財務報表在所有重大方面係依照[適用之財務報導架構]編製，足 以允當表達……」", "如表示保留意見時，除非實務上不可行，應於保留意見之基礎段敘明該等不實表達對財務 報表影響之金額", "如表示否定意見時，否定意見之基礎段應敘明：「本會計師相信已取得足夠及適切之查核 證據，以作為表示否定意見之基礎」", "如表示否定意見時，否定意見段應敘明：「依本會計師之意見，由於否定意見之基礎段所述 事項之影響重大，上開財務報表未依照[適用之財務報導架構]編製，致無法允當表達……」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00847', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '會計師核閱財務報表時，使受核閱者繼續經營之能力可能產生重大疑慮之事件或情況存在重大 不確定性，惟受核閱者已於財務報表適當揭露。此時，會計師應出具何種結論之核閱報告？', '["出具無保留結論之核閱報告，並於核閱報告中納入繼續經營有關之重大不確定性段", "出具無保留結論之核閱報告，並於核閱報告中納入強調事項段", "出具無保留結論之核閱報告，並於核閱報告中納入其他事項段", "出具保留結論之核閱報告，並於核閱報告中納入保留結論之基礎段"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00848', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據我國審計準則公報規定，下列何者非為個別關鍵查核事項應敘述之內容？', '["與財務報表相關揭露之索引（如有相關揭露可供索引時）", "會計師為何判斷該事項為對財務報表之查核最為重要事項之一，因而被決定為關鍵查核事項", "會計師對個別關鍵查核事項所表示之意見", "會計師對關鍵查核事項所採取因應或查核方式之最攸關（或特定）層面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00849', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司財務報表係委由A會計師查核，其子公司乙的財務報表則由B會計師查核並出具無保留 意見報告，乙公司對甲公司財務報表之表達具有重大影響。如A會計師不予信賴B會計師之查 核報告，甲公司又不同意A會計師對乙公司進行查核，A會計師應如何處理此情況？', '["視為查核範圍受限制", "推定乙公司採用之會計政策不適當", "於合併財務報表查核報告「其他事項段」中敘明區分責任", "在合併財務報表查核報告中增列「強調事項段」說明此一情況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": "f5d3c7c51f66", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00850', 'cpa', 'cpa-moex-107-17b9ba7b', 'sub-cpa-04', NULL, 'essay', '甲公司正在設計一款新型手機，並為其編列產品生命週期預算。甲公
